    "summary": "Fold an add of a negative constant applied to an unsigned-maximum clamp into unsigned saturating subtract.",
    "match": {
      "root": "(add T Y, C)",
      "constraints": [
        "T is any integer scalar or integer vector type supported by the involved intrinsics",
        "C is a constant integer splat/value",
